#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long a = (long long)sqrt((double)N);
        while((a+1)*(a+1) <= N) ++a;
        while(a*a > N) --a;
        long long b = N / a;
        long long r = N % a;
        long long len = a + b + (r>0);
        char *ans = (char*)malloc(len+1);
        long long pos = 0;
        if(r==0){
            memset(ans+pos, 'X', a); pos+=a;
            memset(ans+pos, 'D', b); pos+=b;
        }else{
            memset(ans+pos, 'X', r); pos+=r;
            ans[pos++] = 'D';
            memset(ans+pos, 'X', a - r); pos+=a - r;
            memset(ans+pos, 'D', b); pos+=b;
        }
        ans[pos] = '\0';
        printf("%s\n", ans);
        free(ans);
    }
    return 0;
}

