#!/usr/bin/env python3
import sys,math

def solve():
    data = sys.stdin.read().strip().split()
    if not data: return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = int(math.isqrt(N))
        # adjust a to be floor(sqrt(N))
        while (a+1)*(a+1) <= N:
            a += 1
        while a*a > N:
            a -= 1
        b = N // a
        r = N % a
        if r == 0:
            ans = 'X'*a + 'D'*b
        else:
            ans = 'X'*r + 'D' + 'X'*(a-r) + 'D'*b
        out_lines.append(ans)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

