    ans = 'X'.repeat(a) + 'D'.repeat(Number(b));
  } else {
    ans = 'X'.repeat(Number(r)) + 'D' + 'X'.repeat(a - Number(r)) + 'D'.repeat(Number(b));
  }
  outputs.push(ans);
}
